build for javascript backend

create a Items table:
  name, required

create a RateLimits table:
  ip_address, required
  request_count, default 0
  window_start_at, required

when user sends item_data to /api/items:
  ip = 'client'
  now = current time
  one_minute_ago = now minus 60

  existing_limits = get all RateLimits where ip_address is ip

  if length of existing_limits is greater than 0:
    limit_record = first item of existing_limits

    if limit_record's window_start_at is less than one_minute_ago:
      new_limit = { ip_address: ip, request_count: 1, window_start_at: now }
      save new_limit to RateLimits
    else:
      if limit_record's request_count is greater than or equal to 5:
        send back 'rate limited' with status 429

      update_data = { request_count: limit_record's request_count plus 1 }
      save update_data to RateLimits
  else:
    new_limit = { ip_address: ip, request_count: 1, window_start_at: now }
    save new_limit to RateLimits

  validate item_data:
    name is text, required

  saved = save item_data to Items
  send back saved with status 201

when user calls GET /api/items:
  ip = 'client'
  now = current time
  one_minute_ago = now minus 60

  existing_limits = get all RateLimits where ip_address is ip

  if length of existing_limits is greater than 0:
    limit_record = first item of existing_limits

    if limit_record's window_start_at is greater than one_minute_ago:
      if limit_record's request_count is greater than or equal to 5:
        send back 'rate limited' with status 429

      update_data = { request_count: limit_record's request_count plus 1 }
      save update_data to RateLimits
  else:
    new_limit = { ip_address: ip, request_count: 1, window_start_at: now }
    save new_limit to RateLimits

  send back all Items with status 200
